'use client'

import { Product } from '@/lib/types'
import { Card, CardContent } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { Button } from '@/components/ui/button'
import {
  ShoppingCart,
  Heart,
  Star,
  Package,
  Eye,
} from 'lucide-react'
import Image from 'next/image'
import Link from 'next/link'
import { formatPrice, getDiscountPercentage, getStockStatus } from '@/lib/utils'
import { useCartStore } from '@/lib/store'
import { useState } from 'react'
import { cn } from '@/lib/utils'
import { AnimatePresence, motion } from 'framer-motion'

interface ProductCardProps {
  product: Product
  variant?: 'default' | 'compact' | 'featured'
}

export function ProductCard({ product, variant = 'default' }: ProductCardProps) {
  const [isHovered, setIsHovered] = useState(false)
  const [imageError, setImageError] = useState(false)
  const [isWishlisted, setIsWishlisted] = useState(false)
  const addItem = useCartStore((state) => state.addItem)

  const mainImage = product.images?.[0]
  const discount = product.comparePrice
    ? getDiscountPercentage(product.price, product.comparePrice)
    : 0
  const stockStatus = getStockStatus(product.stock)

  const handleAddToCart = (e: React.MouseEvent) => {
    e.preventDefault()
    e.stopPropagation()
    addItem({
      productId: product.id,
      name: product.name,
      price: product.price,
      quantity: 1,
      image: mainImage || '',
      slug: product.slug,
    })
  }

  const handleWishlist = (e: React.MouseEvent) => {
    e.preventDefault()
    e.stopPropagation()
    setIsWishlisted(!isWishlisted)
  }

  if (variant === 'compact') {
    return (
      <Link href={`/product/${product.slug}`}>
        <Card className="group overflow-hidden hover:shadow-lg transition-all duration-300 border-0 bg-gray-50 dark:bg-gray-800">
          <CardContent className="p-4">
            <div className="flex gap-4">
              <div className="relative h-16 w-16 rounded-xl overflow-hidden bg-gray-100 dark:bg-gray-700 flex-shrink-0">
                {mainImage && !imageError ? (
                  <Image
                    src={mainImage}
                    alt={product.name}
                    fill
                    className="object-cover group-hover:scale-110 transition-transform duration-300"
                    onError={() => setImageError(true)}
                  />
                ) : (
                  <div className="h-full w-full flex items-center justify-center">
                    <Package className="h-6 w-6 text-muted-foreground" />
                  </div>
                )}
              </div>
              <div className="flex-1 min-w-0">
                <p className="font-medium text-sm truncate">{product.name}</p>
                <div className="flex items-center gap-1 mt-1">
                  <Star className="h-3 w-3 fill-amber-400 text-amber-400" />
                  <span className="text-xs text-muted-foreground">
                    {product.rating.toFixed(1)}
                  </span>
                </div>
                <p className="font-semibold text-sm mt-1">
                  {formatPrice(product.price)}
                </p>
              </div>
            </div>
          </CardContent>
        </Card>
      </Link>
    )
  }

  return (
    <Link href={`/product/${product.slug}`} className="block h-full">
      <Card
        className={cn(
          "group flex h-full flex-col overflow-hidden border-0 bg-white shadow-lg transition-all duration-500 hover:-translate-y-1 hover:shadow-2xl dark:bg-gray-800",
          variant === 'featured' && "ring-2 ring-emerald-500/20"
        )}
        onMouseEnter={() => setIsHovered(true)}
        onMouseLeave={() => setIsHovered(false)}
      >
        {/* Image Container */}
        <div className="relative aspect-square overflow-hidden bg-gray-100 dark:bg-gray-700">
          {mainImage && !imageError ? (
            <Image
              src={mainImage}
              alt={product.name}
              fill
              className="object-cover group-hover:scale-110 transition-transform duration-700"
              onError={() => setImageError(true)}
            />
          ) : (
            <div className="h-full w-full flex items-center justify-center">
              <Package className="h-16 w-16 text-muted-foreground/50" />
            </div>
          )}

          {/* Overlay */}
          <div className="absolute inset-0 bg-gradient-to-t from-black/40 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300" />

          {/* Badges */}
          <div className="absolute top-4 left-4 flex flex-col gap-2">
            <AnimatePresence>
              {discount > 0 && (
                <motion.div
                  key="discount"
                  initial={{ opacity: 0, x: -20 }}
                  animate={{ opacity: 1, x: 0 }}
                  exit={{ opacity: 0, x: -20 }}
                >
                  <Badge className="bg-red-500 hover:bg-red-600 text-white shadow-lg">
                    -{discount}%
                  </Badge>
                </motion.div>
              )}
              {product.featured && (
                <motion.div
                  key="featured"
                  initial={{ opacity: 0, x: -20 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: 0.1 }}
                >
                  <Badge className="bg-emerald-500 hover:bg-emerald-600 text-white shadow-lg">
                    Featured
                  </Badge>
                </motion.div>
              )}
              {product.trending && (
                <motion.div
                  key="trending"
                  initial={{ opacity: 0, x: -20 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: 0.15 }}
                >
                  <Badge className="bg-amber-500 hover:bg-amber-600 text-white shadow-lg">
                    Trending
                  </Badge>
                </motion.div>
              )}
            </AnimatePresence>
          </div>

          {/* Quick Actions */}
          <div className="absolute top-4 right-4 flex flex-col gap-2">
            <motion.div
              initial={{ opacity: 0, x: 20 }}
              animate={{ opacity: isHovered ? 1 : 0, x: isHovered ? 0 : 20 }}
              transition={{ duration: 0.2 }}
            >
              <Button
                size="icon"
                variant="secondary"
                className={cn(
                  "h-10 w-10 rounded-full shadow-lg backdrop-blur-sm transition-colors",
                  isWishlisted ? "bg-red-500 text-white hover:bg-red-600" : "bg-white/90 hover:bg-white"
                )}
                onClick={handleWishlist}
              >
                <Heart className={cn("h-5 w-5", isWishlisted && "fill-current")} />
              </Button>
            </motion.div>
            <motion.div
              initial={{ opacity: 0, x: 20 }}
              animate={{ opacity: isHovered ? 1 : 0, x: isHovered ? 0 : 20 }}
              transition={{ duration: 0.2, delay: 0.1 }}
            >
              <Button
                size="icon"
                variant="secondary"
                className="h-10 w-10 rounded-full shadow-lg backdrop-blur-sm bg-white/90 hover:bg-white"
                onClick={(e) => {
                  e.preventDefault()
                  e.stopPropagation()
                }}
              >
                <Eye className="h-5 w-5" />
              </Button>
            </motion.div>
          </div>

          {/* Add to Cart Button */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: isHovered ? 1 : 0, y: isHovered ? 0 : 20 }}
            transition={{ duration: 0.2 }}
            className="absolute bottom-4 left-4 right-4"
          >
            <Button
              className="w-full h-12 bg-white text-gray-900 hover:bg-gray-100 shadow-xl rounded-xl font-semibold"
              onClick={handleAddToCart}
              disabled={product.stock === 0}
            >
              <ShoppingCart className="h-5 w-5 mr-2" />
              {product.stock === 0 ? 'Out of Stock' : 'Add to Cart'}
            </Button>
          </motion.div>
        </div>

        {/* Content */}
        <CardContent className="flex flex-1 flex-col p-5">
          {/* Category */}
          {product.category && (
            <p className="text-xs font-medium text-emerald-600 dark:text-emerald-400 mb-2 uppercase tracking-wider">
              {product.category.name}
            </p>
          )}

          {/* Name */}
          <h3 className="font-semibold text-lg line-clamp-2 mb-3 group-hover:text-emerald-600 transition-colors">
            {product.name}
          </h3>

          {/* Rating */}
          <div className="flex items-center gap-2 mb-3">
            <div className="flex items-center gap-0.5">
              {[...Array(5)].map((_, i) => (
                <Star
                  key={i}
                  className={cn(
                    "h-4 w-4",
                    i < Math.floor(product.rating)
                      ? "fill-amber-400 text-amber-400"
                      : "fill-gray-200 text-gray-200 dark:fill-gray-700 dark:text-gray-700"
                  )}
                />
              ))}
            </div>
            <span className="text-sm text-muted-foreground">
              ({product.reviewCount})
            </span>
          </div>

          {/* Price */}
          <div className="flex items-center gap-3 mb-3">
            <span className="text-2xl font-bold">{formatPrice(product.price)}</span>
            {product.comparePrice && (
              <span className="text-base text-muted-foreground line-through">
                {formatPrice(product.comparePrice)}
              </span>
            )}
          </div>

          {/* Stock Status */}
          <div className="mt-auto flex items-center gap-2 pt-2">
            <div className={cn(
              "w-2 h-2 rounded-full",
              stockStatus.status === 'in-stock' && "bg-emerald-500",
              stockStatus.status === 'low-stock' && "bg-amber-500",
              stockStatus.status === 'out-of-stock' && "bg-red-500"
            )} />
            <span className={cn("text-sm", stockStatus.color)}>
              {stockStatus.label}
            </span>
          </div>
        </CardContent>
      </Card>
    </Link>
  )
}

'use client'

import { useState } from 'react'
import { Product } from '@/lib/types'
import { ProductCard } from './ProductCard'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select'
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetTrigger,
} from '@/components/ui/sheet'
import { Slider } from '@/components/ui/slider'
import { Badge } from '@/components/ui/badge'
import {
  SlidersHorizontal,
  Grid3X3,
  LayoutGrid,
  Search,
  X,
} from 'lucide-react'
import { useFilterStore, ProductFilters } from '@/lib/store'
import { formatPrice, cn } from '@/lib/utils'

interface ProductGridProps {
  products: Product[]
  total: number
  categories?: { id: string; name: string; slug: string }[]
}

interface ActiveFiltersProps {
  filters: ProductFilters
  categories: { id: string; name: string; slug: string }[]
  setFilter: <K extends keyof ProductFilters>(key: K, value: ProductFilters[K]) => void
  resetFilters: () => void
  activeFiltersCount: number
}

function ActiveFilters({ filters, categories, setFilter, resetFilters, activeFiltersCount }: ActiveFiltersProps) {
  return (
    <div className="flex flex-wrap gap-2">
      {filters.category && (
        <Badge variant="secondary" className="gap-1">
          Category: {categories.find(c => c.slug === filters.category)?.name}
          <X
            className="h-3 w-3 cursor-pointer"
            onClick={() => setFilter('category', null)}
          />
        </Badge>
      )}
      {filters.minPrice && (
        <Badge variant="secondary" className="gap-1">
          Min: {formatPrice(filters.minPrice)}
          <X
            className="h-3 w-3 cursor-pointer"
            onClick={() => setFilter('minPrice', null)}
          />
        </Badge>
      )}
      {filters.maxPrice && (
        <Badge variant="secondary" className="gap-1">
          Max: {formatPrice(filters.maxPrice)}
          <X
            className="h-3 w-3 cursor-pointer"
            onClick={() => setFilter('maxPrice', null)}
          />
        </Badge>
      )}
      {filters.rating && (
        <Badge variant="secondary" className="gap-1">
          {filters.rating}+ Stars
          <X
            className="h-3 w-3 cursor-pointer"
            onClick={() => setFilter('rating', null)}
          />
        </Badge>
      )}
      {filters.inStock && (
        <Badge variant="secondary" className="gap-1">
          In Stock
          <X
            className="h-3 w-3 cursor-pointer"
            onClick={() => setFilter('inStock', false)}
          />
        </Badge>
      )}
      {activeFiltersCount > 0 && (
        <Button
          variant="ghost"
          size="sm"
          className="h-6 text-xs"
          onClick={resetFilters}
        >
          Clear all
        </Button>
      )}
    </div>
  )
}

interface FilterContentProps {
  categories: { id: string; name: string; slug: string }[]
  filters: ProductFilters
  setFilter: <K extends keyof ProductFilters>(key: K, value: ProductFilters[K]) => void
  resetFilters: () => void
  priceRange: number[]
  setPriceRange: (value: number[]) => void
  activeFiltersCount: number
}

function FilterContent({ 
  categories, 
  filters, 
  setFilter, 
  resetFilters, 
  priceRange, 
  setPriceRange,
  activeFiltersCount 
}: FilterContentProps) {
  return (
    <div className="space-y-6">
      {/* Categories */}
      <div>
        <Label className="text-base font-semibold">Categories</Label>
        <div className="mt-3 space-y-2">
          {categories.map((category) => (
            <Button
              key={category.id}
              variant={filters.category === category.slug ? 'default' : 'ghost'}
              className="w-full justify-start"
              onClick={() =>
                setFilter(
                  'category',
                  filters.category === category.slug ? null : category.slug
                )
              }
            >
              {category.name}
            </Button>
          ))}
        </div>
      </div>

      {/* Price Range */}
      <div>
        <Label className="text-base font-semibold">Price Range</Label>
        <div className="mt-3 px-2">
          <Slider
            value={priceRange}
            onValueChange={setPriceRange}
            max={1000}
            step={10}
            className="mb-4"
          />
          <div className="flex items-center justify-between text-sm text-muted-foreground">
            <span>{formatPrice(priceRange[0])}</span>
            <span>{formatPrice(priceRange[1])}</span>
          </div>
          <Button
            className="w-full mt-3"
            size="sm"
            onClick={() => {
              setFilter('minPrice', priceRange[0])
              setFilter('maxPrice', priceRange[1])
            }}
          >
            Apply
          </Button>
        </div>
      </div>

      {/* Rating */}
      <div>
        <Label className="text-base font-semibold">Rating</Label>
        <div className="mt-3 space-y-2">
          {[4, 3, 2, 1].map((rating) => (
            <Button
              key={rating}
              variant={filters.rating === rating ? 'default' : 'ghost'}
              className="w-full justify-start"
              onClick={() =>
                setFilter('rating', filters.rating === rating ? null : rating)
              }
            >
              {rating}+ Stars
            </Button>
          ))}
        </div>
      </div>

      {/* In Stock */}
      <div>
        <Button
          variant={filters.inStock ? 'default' : 'outline'}
          className="w-full"
          onClick={() => setFilter('inStock', !filters.inStock)}
        >
          In Stock Only
        </Button>
      </div>

      {/* Reset */}
      {activeFiltersCount > 0 && (
        <Button variant="destructive" className="w-full" onClick={resetFilters}>
          Clear All Filters
        </Button>
      )}
    </div>
  )
}

export function ProductGrid({ products, total, categories = [] }: ProductGridProps) {
  const [gridView, setGridView] = useState<'grid' | 'list'>('grid')
  const { filters, setFilter, resetFilters } = useFilterStore()
  const [priceRange, setPriceRange] = useState([0, 1000])
  const [filterOpen, setFilterOpen] = useState(false)

  const activeFiltersCount = [
    filters.category,
    filters.minPrice,
    filters.maxPrice,
    filters.rating,
    filters.inStock,
  ].filter(Boolean).length

  const filteredProducts = products
    .filter((product) => {
      const matchesCategory = !filters.category || product.category?.slug === filters.category
      const searchTerm = filters.search.trim().toLowerCase()
      const matchesSearch =
        !searchTerm ||
        product.name.toLowerCase().includes(searchTerm) ||
        product.description.toLowerCase().includes(searchTerm)
      const matchesMinPrice = filters.minPrice === null || product.price >= filters.minPrice
      const matchesMaxPrice = filters.maxPrice === null || product.price <= filters.maxPrice
      const matchesRating = filters.rating === null || product.rating >= filters.rating
      const matchesStock = !filters.inStock || product.stock > 0

      return (
        matchesCategory &&
        matchesSearch &&
        matchesMinPrice &&
        matchesMaxPrice &&
        matchesRating &&
        matchesStock
      )
    })
    .sort((a, b) => {
      switch (filters.sort) {
        case 'price-asc':
          return a.price - b.price
        case 'price-desc':
          return b.price - a.price
        case 'rating':
          return b.rating - a.rating
        case 'popular':
          return b.reviewCount - a.reviewCount
        default:
          return new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
      }
    })

  return (
    <div id="products" className="space-y-8">
      {/* Header */}
      <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
        <div className="max-w-2xl text-center sm:text-left">
          <h2 className="text-3xl font-bold tracking-tight">All Products</h2>
          <p className="mt-2 text-muted-foreground">
            {filteredProducts.length} of {total} products shown
          </p>
        </div>

        <div className="flex flex-wrap items-center justify-center gap-2 sm:justify-end">
          {/* Search */}
          <div className="relative min-w-[220px] flex-1 sm:w-64">
            <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
            <Input
              placeholder="Search..."
              value={filters.search}
              onChange={(e) => setFilter('search', e.target.value)}
              className="pl-9"
            />
          </div>

          {/* Sort */}
          <Select
            value={filters.sort}
            onValueChange={(value: ProductFilters['sort']) => setFilter('sort', value)}
          >
            <SelectTrigger className="w-[140px]">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="newest">Newest</SelectItem>
              <SelectItem value="price-asc">Price: Low to High</SelectItem>
              <SelectItem value="price-desc">Price: High to Low</SelectItem>
              <SelectItem value="rating">Top Rated</SelectItem>
              <SelectItem value="popular">Most Popular</SelectItem>
            </SelectContent>
          </Select>

          {/* Filter Button - Mobile */}
          <Sheet open={filterOpen} onOpenChange={setFilterOpen}>
            <SheetTrigger asChild>
              <Button variant="outline" size="icon" className="lg:hidden">
                <SlidersHorizontal className="h-4 w-4" />
                {activeFiltersCount > 0 && (
                  <span className="absolute -top-1 -right-1 h-4 w-4 rounded-full bg-emerald-500 text-[10px] font-medium text-white flex items-center justify-center">
                    {activeFiltersCount}
                  </span>
                )}
              </Button>
            </SheetTrigger>
            <SheetContent side="left" className="w-80">
              <SheetHeader>
                <SheetTitle>Filters</SheetTitle>
              </SheetHeader>
              <div className="mt-6">
                <FilterContent 
                  categories={categories}
                  filters={filters}
                  setFilter={setFilter}
                  resetFilters={resetFilters}
                  priceRange={priceRange}
                  setPriceRange={setPriceRange}
                  activeFiltersCount={activeFiltersCount}
                />
              </div>
            </SheetContent>
          </Sheet>

          {/* Grid Toggle */}
          <div className="hidden sm:flex border rounded-lg p-1">
            <Button
              variant={gridView === 'grid' ? 'secondary' : 'ghost'}
              size="icon"
              className="h-8 w-8"
              onClick={() => setGridView('grid')}
            >
              <Grid3X3 className="h-4 w-4" />
            </Button>
            <Button
              variant={gridView === 'list' ? 'secondary' : 'ghost'}
              size="icon"
              className="h-8 w-8"
              onClick={() => setGridView('list')}
            >
              <LayoutGrid className="h-4 w-4" />
            </Button>
          </div>
        </div>
      </div>

      {/* Active Filters */}
      <ActiveFilters 
        filters={filters}
        categories={categories}
        setFilter={setFilter}
        resetFilters={resetFilters}
        activeFiltersCount={activeFiltersCount}
      />

      <div className="flex gap-6 xl:gap-8">
        {/* Desktop Filters Sidebar */}
        <aside className="hidden lg:block w-64 flex-shrink-0">
          <div className="sticky top-20">
            <h3 className="font-semibold mb-4">Filters</h3>
            <FilterContent 
              categories={categories}
              filters={filters}
              setFilter={setFilter}
              resetFilters={resetFilters}
              priceRange={priceRange}
              setPriceRange={setPriceRange}
              activeFiltersCount={activeFiltersCount}
            />
          </div>
        </aside>

        {/* Products Grid */}
        <div className="flex-1">
          {filteredProducts.length === 0 ? (
            <div className="text-center py-12">
              <p className="text-muted-foreground">No products found</p>
              <Button variant="link" onClick={resetFilters}>
                Clear filters
              </Button>
            </div>
          ) : (
            <div
              className={cn(
                "grid gap-6",
                gridView === 'grid'
                  ? "grid-cols-1 sm:grid-cols-2 xl:grid-cols-3"
                  : "grid-cols-1"
              )}
            >
              {filteredProducts.map((product) => (
                <ProductCard
                  key={product.id}
                  product={product}
                  variant={gridView === 'list' ? 'default' : 'default'}
                />
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  )
}

